namespace sv_0da0d13e68dd4ca387b1a09e338f7f81.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@* Vertical sidebar navigation for settings sections *@

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted mb-1">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link settings-nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="settings-nav-icon">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

@using sv_0da0d13e68dd4ca387b1a09e338f7f81.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Profile Settings</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4">
                <div class="card text-center p-3">
                    <div class="avatar-preview mb-3">
                        @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" style="width:100px;height:100px;object-fit:cover;" />
                        }
                        else
                        {
                            <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center mx-auto"
                                 style="width:100px;height:100px;">
                                <span class="text-white fs-1">👤</span>
                            </div>
                        }
                    </div>
                    <label class="form-label fw-semibold">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="mt-4 d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
                Discard Changes
            </button>
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        try
        {
            _savedProfile = await SettingsService.GetProfileAsync();
            ApplyProfile(_savedProfile);
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _message = "Profile saved successfully!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save profile: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _message = null;
    }
}

@using sv_0da0d13e68dd4ca387b1a09e338f7f81.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">General</h6>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                    <label class="form-check-label" for="emailNotif">
                        Email Notifications
                        <small class="d-block text-muted">Receive notifications via email</small>
                    </label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                    <label class="form-check-label" for="pushNotif">
                        Push Notifications
                        <small class="d-block text-muted">Receive push notifications in your browser</small>
                    </label>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">
                        Weekly Digest
                        <small class="d-block text-muted">Get a weekly summary of activity</small>
                    </label>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Muted Channels</h6>
                @if (_allChannels.Count == 0)
                {
                    <p class="text-muted">No channels available.</p>
                }
                else
                {
                    @foreach (var channel in _allChannels)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"ch-{channel}")">
                                @channel
                            </label>
                        </div>
                    }
                }
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();

    // Known channels — in a real app these might come from another service
    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save preferences: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

