@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
        ["zh"] = "中文"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private string GetPreviewClasses()
    {
        return _theme == "Dark" ? "text-light" : "";
    }

    private string GetPreviewStyles()
    {
        var bg = _theme == "Dark" ? "background-color:#1e1e2e;color:#cdd6f4;" : "background-color:#ffffff;";
        var padding = _compactMode ? "padding:0.5rem;" : "padding:1rem;";
        return $"{bg}{padding}";
    }

    private string GetPreviewFontStyle()
    {
        var size = _fontSize switch
        {
            "Small" => "font-size:0.8rem;",
            "Large" => "font-size:1.15rem;",
            _ => "font-size:0.95rem;"
        };
        return size;
    }

    private string GetPreviewCardStyle()
    {
        return _theme == "Dark"
            ? "background-color:#313244;border:1px solid #45475a;"
            : "background-color:#f8f9fa;border:1px solid #dee2e6;";
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _message = "Appearance settings saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save settings: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

