        {
            _message = $"Failed to save profile: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _message = null;
    }
}
"}

{"path": "/tmp/sv-0da0d13e68dd4ca387b1a09e338f7f81/Components/Pages/Settings/NotificationsSection.razor", "file_text": "@using sv_0da0d13e68dd4ca387b1a09e338f7f81.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">General</h6>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                    <label class="form-check-label" for="emailNotif">
                        Email Notifications
                        <small class="d-block text-muted">Receive notifications via email</small>
                    </label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                    <label class="form-check-label" for="pushNotif">
                        Push Notifications
                        <small class="d-block text-muted">Receive push notifications in your browser</small>
                    </label>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">
                        Weekly Digest
                        <small class="d-block text-muted">Get a weekly summary of activity</small>
                    </label>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Muted Channels</h6>
                @if (_allChannels.Count == 0)
                {
                    <p class="text-muted">No channels available.</p>
                }
                else
                {
                    @foreach (var channel in _allChannels)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"ch-{channel}")">
                                @channel
                            </label>
                        </div>
                    }
                }
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();

    // Known channels — in a real app these might come from another service
    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save preferences: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}
"}

{"path": "/tmp/sv-0da0d13e68dd4ca387b1a09e338f7f81/Components/Pages/Settings/SecuritySection.razor", "file_text": "@using sv_0da0d13e68dd4ca387b1a09e338f7f81.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        @* Change Password Panel *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 style="cursor:pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <h6 class="mb-0">Change Password</h6>
                <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (!string.IsNullOrEmpty(_passwordMessage))
                    {
                        <div class="alert @(_passwordIsError ? "alert-danger" : "alert-success") py-2" role="alert">
                            @_passwordMessage
                        </div>
                    }

                    <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>

                    @if (_settings?.LastPasswordChange is not null)
                    {
                        <small class="text-muted ms-3">
                            Last changed: @_settings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                        </small>
                    }
                </div>
            }
        </div>

        @* Two-Factor Authentication *@
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(_settings!.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" checked="@_settings.TwoFactorEnabled" disabled
                           style="transform: scale(1.4);" />
                </div>
            </div>
        </div>

        @* Active Sessions *@
        <div class="card mb-4">
            <div class="card-header">
                <h6 class="mb-0">Active Sessions</h6>
            </div>
            <div class="card-body p-0">
                @if (_settings!.Sessions.Count == 0)
                {
                    <p class="text-muted p-3">No active sessions.</p>
                }
                else
                {
                    <div class="table-responsive">
                        <table class="table table-hover mb-0">
                            <thead class="table-light">
                                <tr>
                                    <th>Device</th>
                                    <th>Location</th>
                                    <th>Last Active</th>
                                    <th class="text-end">Action</th>
                                </tr>
                            </thead>
                            <tbody>
                                @foreach (var session in _settings.Sessions)
                                {
                                    var isCurrent = session == _settings.Sessions[0];
                                    <tr>
                                        <td>
                                            @session.Device
                                            @if (isCurrent)
                                            {
                                                <span class="badge bg-primary ms-1">Current</span>
                                            }
                                        </td>
                                        <td>@session.Location</td>
                                        <td>@session.LastActive.ToString("MMM d, yyyy h:mm tt")</td>
                                        <td class="text-end">
                                            @if (!isCurrent)
                                            {
                                                <button class="btn btn-outline-danger btn-sm"
                                                        @onclick="() => PromptRevoke(session)">
                                                    Revoke
                                                </button>
                                            }
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    </div>
                }
            </div>
        </div>

        @* Revoke Confirmation Dialog *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal fade show d-block" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered" role="document">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>
                                Are you sure you want to revoke the session on
                                <strong>@_sessionToRevoke.Device</strong> from
                                <strong>@_sessionToRevoke.Location</strong>?
                            </p>
                            <p class="text-muted small">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@_revoking">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke Session
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private SecuritySettings? _settings;
    private bool _loading = true;

    // Password change
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordMessage;
    private bool _passwordIsError;

    // Session revoke
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            _settings = await SettingsService.GetSecuritySettingsAsync();
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task ChangePasswordAsync()
    {
        _passwordMessage = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordMessage = "New password cannot be empty.";
            _passwordIsError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordMessage = "New password and confirmation do not match.";
            _passwordIsError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordMessage = "Password updated successfully!";
            _passwordIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordMessage = $"Failed to change password: {ex.Message}";
            _passwordIsError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }
}
"}

{"path": "/tmp/sv-0da0d13e68dd4ca387b1a09e338f7f81/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@using sv_0da0d13e68dd4ca387b1a09e338f7f81.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                @* Theme *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Theme</h6>
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme.ToLower()}")"
                                       value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme.ToLower()}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                @* Font Size *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Font Size</h6>
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size.ToLower()}")"
                                       value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size.ToLower()}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                @* Language *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang.Key">@lang.Value</option>
                            }
                        </select>
                    </div>
                </div>

                @* Compact Mode *@
                <div class="card mb-4">
                    <div class="card-body">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                            <label class="form-check-label" for="compactMode">
                                Compact Mode
                                <small class="d-block text-muted">Reduce spacing and padding throughout the UI</small>
                            </label>
                        </div>
                    </div>
                </div>
            </div>

            @* Live Preview *@
            <div class="col-md-5">
                <div class="card sticky-top" style="top: 1rem;">
                    <div class="card-header">
                        <h6 class="mb-0">Preview</h6>
                    </div>
                    <div class="card-body @GetPreviewClasses()" style="@GetPreviewStyles()">
                        <h6 style="@GetPreviewFontStyle()">Dashboard</h6>
                        <p style="@GetPreviewFontStyle()" class="@(_compactMode ? "mb-1" : "mb-3")">
                            This is a preview of how your content will look with the selected settings.
                        </p>
                        <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                            <span class="badge bg-primary">Badge</span>
                            <span class="badge bg-success">Active</span>
                            <span class="badge bg-warning text-dark">Pending</span>
                        </div>
                        <button class="btn btn-sm btn-primary me-1">Primary</button>
                        <button class="btn btn-sm btn-outline-secondary">Secondary</button>

                        <hr class="@(_compactMode ? "my-2" : "my-3")" />

                        <div class="@(_compactMode ? "p-1" : "p-2") rounded"
                             style="@GetPreviewCardStyle()">
                            <small style="@GetPreviewFontStyle()">
                                <strong>Card Example</strong><br />
                                Content inside a nested card element.
                            </small>
                        </div>

                        <div class="mt-2 text-end">
                            <small class="text-muted">
                                @_theme · @_fontSize · @_languages.GetValueOrDefault(_language, _language)
                            </small>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save
            </button>
        </div>
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
        ["zh"] = "中文"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private string GetPreviewClasses()
    {
        return _theme == "Dark" ? "text-light" : "";
    }

    private string GetPreviewStyles()
    {
        var bg = _theme == "Dark" ? "background-color:#1e1e2e;color:#cdd6f4;" : "background-color:#ffffff;";
        var padding = _compactMode ? "padding:0.5rem;" : "padding:1rem;";
        return $"{bg}{padding}";
    }

    private string GetPreviewFontStyle()
    {
        var size = _fontSize switch
        {
            "Small" => "font-size:0.8rem;",
            "Large" => "font-size:1.15rem;",
            _ => "font-size:0.95rem;"
        };
        return size;
    }

    private string GetPreviewCardStyle()
    {
        return _theme == "Dark"
            ? "background-color:#313244;border:1px solid #45475a;"
            : "background-color:#f8f9fa;border:1px solid #dee2e6;";
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _message = "Appearance settings saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save settings: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}
"}

