@using sv_0da0d13e68dd4ca387b1a09e338f7f81.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">General</h6>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                    <label class="form-check-label" for="emailNotif">
                        Email Notifications
                        <small class="d-block text-muted">Receive notifications via email</small>
                    </label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                    <label class="form-check-label" for="pushNotif">
                        Push Notifications
                        <small class="d-block text-muted">Receive push notifications in your browser</small>
                    </label>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">
                        Weekly Digest
                        <small class="d-block text-muted">Get a weekly summary of activity</small>
                    </label>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Muted Channels</h6>
                @if (_allChannels.Count == 0)
                {
                    <p class="text-muted">No channels available.</p>
                }
                else
                {
                    @foreach (var channel in _allChannels)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"ch-{channel}")">
                                @channel
                            </label>
                        </div>
                    }
                }
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();

    // Known channels — in a real app these might come from another service
    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save preferences: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

