toolArgs.file_text:
@using sv_0da0d13e68dd4ca387b1a09e338f7f81.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                @* Theme *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Theme</h6>
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme.ToLower()}")"
                                       value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme.ToLower()}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                @* Font Size *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Font Size</h6>
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size.ToLower()}")"
                                       value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size.ToLower()}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                @* Language *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang.Key">@lang.Value</option>
                            }
                        </select>
                    </div>
                </div>

                @* Compact Mode *@
                <div class="card mb-4">
                    <div class="card-body">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                            <label class="form-check-label" for="compactMode">
                                Compact Mode
                                <small class="d-block text-muted">Reduce spacing and padding throughout the UI</small>
                            </label>
                        </div>
                    </div>
                </div>
            </div>

            @* Live Preview *@
            <div class="col-md-5">
                <div class="card sticky-top" style="top: 1rem;">
                    <div class="card-header">
                        <h6 class="mb-0">Preview</h6>
                    </div>
                    <div class="card-body @GetPreviewClasses()" style="@GetPreviewStyles()">
                        <h6 style="@GetPreviewFontStyle()">Dashboard</h6>
                        <p style="@GetPreviewFontStyle()" class="@(_compactMode ? "mb-1" : "mb-3")">
                            This is a preview of how your content will look with the selected settings.
                        </p>
                        <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                            <span class="badge bg-primary">Badge</span>
                            <span class="badge bg-success">Active</span>
                            <span class="badge bg-warning text-dark">Pending</span>
                        </div>
                        <button class="btn btn-sm btn-primary me-1">Primary</button>
                        <button class="btn btn-sm btn-outline-secondary">Secondary</button>

                        <hr class="@(_compactMode ? "my-2" : "my-3")" />

                        <div class="@(_compactMode ? "p-1" : "p-2") rounded"
                             style="@GetPreviewCardStyle()">
                            <small style="@GetPreviewFontStyle()">
                                <strong>Card Example</strong><br />
                                Content inside a nested card element.
                            </small>
                        </div>

                        <div class="mt-2 text-end">
                            <small class="text-muted">
                                @_theme · @_fontSize · @_languages.GetValueOrDefault(_language, _language)
                            </small>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save
            </button>
        </div>
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
        ["zh"] = "中文"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private string GetPreviewClasses()
    {
        return _theme == "Dark" ? "text-light" : "";
    }

    private string GetPreviewStyles()
    {
        var bg = _theme == "Dark" ? "background-color:#1e1e2e;color:#cdd6f4;" : "background-color:#ffffff;";
        var padding = _compactMode ? "padding:0.5rem;" : "padding:1rem;";
        return $"{bg}{padding}";
    }

    private string GetPreviewFontStyle()
    {
        var size = _fontSize switch
        {
            "Small" => "font-size:0.8rem;",
            "Large" => "font-size:1.15rem;",
            _ => "font-size:0.95rem;"
        };
        return size;
    }

    private string GetPreviewCardStyle()
    {
        return _theme == "Dark"
            ? "background-color:#313244;border:1px solid #45475a;"
            : "background-color:#f8f9fa;border:1px solid #dee2e6;";
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _message = "Appearance settings saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save settings: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

