toolArgs.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <div class="settings-sidebar-container">
        <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />
    </div>

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";
}

.settings-dashboard {
    display: flex;
    gap: 2rem;
    min-height: calc(100vh - 120px);
}

.settings-sidebar-container {
    flex: 0 0 220px;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-sidebar {
    position: sticky;
    top: 1rem;
}

::deep .settings-sidebar h5 {
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

::deep .settings-nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
    border: none;
    background: none;
    padding: 0.6rem 1rem;
    border-radius: 0.375rem;
    color: #495057;
    font-size: 0.95rem;
    text-align: left;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

::deep .settings-nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

::deep .settings-nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

::deep .settings-nav-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

::deep .settings-section {
    max-width: 900px;
}

@media (max-width: 768px) {
    .settings-dashboard {
        flex-direction: column;
        gap: 1rem;
    }

    .settings-sidebar-container {
        flex: none;
    }

    ::deep .settings-sidebar .nav {
        flex-direction: row;
        overflow-x: auto;
    }

    ::deep .settings-sidebar .nav-item {
        flex: none;
    }
}

